import React, { useState, useEffect } from 'react';
import './PrescriptionGenerator.css';

const PrescriptionGenerator = () => {
    const [patients, setPatients] = useState([
        { id: "P001", name: "John Doe", age: 45, gender: "Male", weight: "75 kg" },
        { id: "P002", name: "Jane Smith", age: 32, gender: "Female", weight: "62 kg" },
        { id: "P003", name: "Robert Johnson", age: 58, gender: "Male", weight: "80 kg" },
        { id: "P004", name: "Sarah Williams", age: 28, gender: "Female", weight: "55 kg" },
    ]);

    const [medicines, setMedicines] = useState([
        { id: 1, name: "Paracetamol", use: "Fever, Pain relief", dosage: "500mg, 1 tab every 6 hours" },
        { id: 2, name: "Amoxicillin", use: "Bacterial infections", dosage: "500mg, 1 tab every 8 hours" },
        { id: 3, name: "Ibuprofen", use: "Inflammation, Pain relief", dosage: "400mg, 1 tab every 8 hours" },
        { id: 4, name: "Cetirizine", use: "Allergies, Hay fever", dosage: "10mg, 1 tab daily" },
        { id: 5, name: "Omeprazole", use: "Acid reflux, GERD", dosage: "20mg, 1 tab daily before food" },
    ]);

    const [prescription, setPrescription] = useState({
        patientId: '',
        diagnosis: '',
        patientAge: '',
        patientGender: '',
        patientWeight: '',
        medicines: [],
        notes: '',
        customMedicines: [] // For custom medicines not in DB
    });

    const [selectedMedicine, setSelectedMedicine] = useState('');
    const [showCustomMedicine, setShowCustomMedicine] = useState(false);
    const [customMedicine, setCustomMedicine] = useState({
        name: '',
        dosage: '',
        duration: '',
        instructions: ''
    });
    const [suggestions, setSuggestions] = useState([]);

    const diagnosisMapping = {
        "fever": ["Paracetamol", "Ibuprofen"],
        "cold": ["Paracetamol", "Cetirizine"],
        "infection": ["Amoxicillin"],
        "pain": ["Paracetamol", "Ibuprofen"],
        "allergy": ["Cetirizine"],
        "acid reflux": ["Omeprazole"],
        "headache": ["Paracetamol"],
        "bp": ["Amlodipine", "Lisinopril"],
        "diabetes": ["Metformin"],
        "cough": ["Dextromethorphan", "Guaifenesin"],
    };

    // Load patient details when patient is selected
    useEffect(() => {
        if (prescription.patientId) {
            const selectedPatient = patients.find(p => p.id === prescription.patientId);
            if (selectedPatient) {
                setPrescription(prev => ({
                    ...prev,
                    patientAge: selectedPatient.age || '',
                    patientGender: selectedPatient.gender || '',
                    patientWeight: selectedPatient.weight || ''
                }));
            }
        }
    }, [prescription.patientId, patients]);

    const handleDiagnosisChange = (e) => {
        const diagnosis = e.target.value;
        setPrescription({ ...prescription, diagnosis });

        if (diagnosis) {
            const keywords = diagnosis.toLowerCase().split(' ');
            const suggested = new Set();

            keywords.forEach(keyword => {
                if (diagnosisMapping[keyword]) {
                    diagnosisMapping[keyword].forEach(med => suggested.add(med));
                }
            });

            // Also check for partial matches
            Object.keys(diagnosisMapping).forEach(key => {
                if (diagnosis.toLowerCase().includes(key)) {
                    diagnosisMapping[key].forEach(med => suggested.add(med));
                }
            });

            setSuggestions(Array.from(suggested));
        } else {
            setSuggestions([]);
        }
    };

    const handleAddMedicine = () => {
        if (selectedMedicine) {
            const medicine = medicines.find(m => m.name === selectedMedicine);
            if (medicine && !prescription.medicines.find(m => m.name === medicine.name)) {
                setPrescription({
                    ...prescription,
                    medicines: [...prescription.medicines, {
                        name: medicine.name,
                        dosage: medicine.dosage,
                        duration: '',
                        instructions: ''
                    }]
                });
                setSelectedMedicine('');
            }
        }
    };

    const handleAddCustomMedicine = () => {
        if (customMedicine.name && customMedicine.dosage) {
            setPrescription({
                ...prescription,
                medicines: [...prescription.medicines, {
                    name: customMedicine.name,
                    dosage: customMedicine.dosage,
                    duration: customMedicine.duration || '',
                    instructions: customMedicine.instructions || '',
                    isCustom: true
                }]
            });
            setCustomMedicine({ name: '', dosage: '', duration: '', instructions: '' });
            setShowCustomMedicine(false);
        } else {
            alert('Please enter at least medicine name and dosage');
        }
    };

    const handleAddSuggestedMedicine = (medicineName) => {
        const medicine = medicines.find(m => m.name === medicineName);
        if (medicine && !prescription.medicines.find(m => m.name === medicineName)) {
            setPrescription({
                ...prescription,
                medicines: [...prescription.medicines, {
                    name: medicine.name,
                    dosage: medicine.dosage,
                    duration: '',
                    instructions: ''
                }]
            });
        }
    };

    const handleRemoveMedicine = (index) => {
        const newMedicines = [...prescription.medicines];
        newMedicines.splice(index, 1);
        setPrescription({ ...prescription, medicines: newMedicines });
    };

    const handleMedicineDetailChange = (index, field, value) => {
        const updatedMedicines = [...prescription.medicines];
        updatedMedicines[index] = { ...updatedMedicines[index], [field]: value };
        setPrescription({ ...prescription, medicines: updatedMedicines });
    };

    const handleGeneratePrescription = () => {
        if (!prescription.patientId) {
            alert('Please select a patient');
            return;
        }

        // All other fields are optional - just generate with what's provided
        const printWindow = window.open('', '_blank');
        const patient = patients.find(p => p.id === prescription.patientId);

        const currentDate = new Date().toLocaleDateString('en-US', { 
            year: 'numeric', 
            month: 'long', 
            day: 'numeric' 
        });

        printWindow.document.write(`
            <html>
                <head>
                    <title>Prescription - ${patient.name}</title>
                    <style>
                        body { 
                            font-family: 'Arial', sans-serif; 
                            margin: 40px; 
                            line-height: 1.6;
                            color: #333;
                        }
                        .header { 
                            text-align: center; 
                            border-bottom: 2px solid #2563EB; 
                            padding-bottom: 20px; 
                            margin-bottom: 30px; 
                        }
                        .clinic-name {
                            color: #2563EB;
                            font-size: 28px;
                            margin-bottom: 5px;
                        }
                        .patient-info { 
                            margin-bottom: 30px; 
                            padding: 20px;
                            background: #F8FAFC;
                            border-radius: 10px;
                        }
                        .medicines { 
                            margin-bottom: 30px; 
                        }
                        .medicine-item { 
                            margin-bottom: 15px; 
                            padding: 15px;
                            background: #F8FAFC;
                            border-radius: 8px;
                            border-left: 4px solid #2563EB;
                        }
                        .footer { 
                            margin-top: 50px; 
                            border-top: 1px solid #ccc; 
                            padding-top: 20px; 
                            text-align: right; 
                        }
                        .label {
                            font-weight: bold;
                            color: #64748B;
                        }
                        .value {
                            margin-left: 10px;
                        }
                        .row {
                            margin-bottom: 10px;
                        }
                    </style>
                </head>
                <body>
                    <div class="header">
                        <h1 class="clinic-name">MediCare Clinic</h1>
                        <p>123 Health Street, Medical City</p>
                        <p>Phone: (123) 456-7890 | Email: contact@medicare.com</p>
                    </div>

                    <div class="patient-info">
                        <h2>Prescription</h2>
                        <div class="row"><span class="label">Date:</span> <span class="value">${currentDate}</span></div>
                        <div class="row"><span class="label">Patient:</span> <span class="value">${patient.name} (${patient.id})</span></div>
                        ${prescription.patientAge ? `<div class="row"><span class="label">Age:</span> <span class="value">${prescription.patientAge}</span></div>` : ''}
                        ${prescription.patientGender ? `<div class="row"><span class="label">Gender:</span> <span class="value">${prescription.patientGender}</span></div>` : ''}
                        ${prescription.patientWeight ? `<div class="row"><span class="label">Weight:</span> <span class="value">${prescription.patientWeight}</span></div>` : ''}
                        ${prescription.diagnosis ? `<div class="row"><span class="label">Diagnosis:</span> <span class="value">${prescription.diagnosis}</span></div>` : ''}
                    </div>

                    <div class="medicines">
                        <h3>Medications:</h3>
                        ${prescription.medicines.map(med => `
                            <div class="medicine-item">
                                <div class="row"><strong>${med.name}</strong> - ${med.dosage}</div>
                                ${med.duration ? `<div class="row"><span class="label">Duration:</span> ${med.duration}</div>` : ''}
                                ${med.instructions ? `<div class="row"><span class="label">Instructions:</span> ${med.instructions}</div>` : ''}
                            </div>
                        `).join('')}
                    </div>

                    ${prescription.notes ? `
                    <div class="notes">
                        <h3>Additional Notes:</h3>
                        <p>${prescription.notes}</p>
                    </div>
                    ` : ''}

                    <div class="footer">
                        <div class="signature">
                            <p>___________________</p>
                            <p><strong>Dr. John Smith</strong></p>
                            <p>MBBS, MD</p>
                            <p>License No: MED123456</p>
                        </div>
                    </div>
                </body>
            </html>
        `);

        printWindow.document.close();
        printWindow.focus();
        setTimeout(() => {
            printWindow.print();
        }, 500);
    };

    const handleClearPrescription = () => {
        setPrescription({
            patientId: '',
            diagnosis: '',
            patientAge: '',
            patientGender: '',
            patientWeight: '',
            medicines: [],
            notes: ''
        });
        setSuggestions([]);
        setSelectedMedicine('');
        setShowCustomMedicine(false);
    };

    const selectedPatient = patients.find(p => p.id === prescription.patientId);

    return (
        <div className="prescription-generator">
            <h2><i className="fas fa-prescription"></i> Prescription Generator</h2>

            <div className="prescription-layout">
                {/* Left Column - Form */}
                <div className="prescription-form-container">
                    <div className="form-section">
                        <h3>Patient Information</h3>

                        <div className="form-group">
                            <label>Select Patient <span className="optional">*</span></label>
                            <select
                                value={prescription.patientId}
                                onChange={(e) => setPrescription({...prescription, patientId: e.target.value})}
                            >
                                <option value="">Select a patient</option>
                                {patients.map(patient => (
                                    <option key={patient.id} value={patient.id}>
                                        {patient.name} ({patient.id}) - {patient.age} yrs
                                    </option>
                                ))}
                            </select>
                        </div>

                        {selectedPatient && (
                            <div className="patient-details">
                                <div className="detail-row">
                                    <span className="detail-label">Age:</span>
                                    <input
                                        type="text"
                                        value={prescription.patientAge}
                                        onChange={(e) => setPrescription({...prescription, patientAge: e.target.value})}
                                        placeholder="Age"
                                        className="detail-input"
                                    />
                                    <span className="detail-label">Gender:</span>
                                    <select
                                        value={prescription.patientGender}
                                        onChange={(e) => setPrescription({...prescription, patientGender: e.target.value})}
                                        className="detail-select"
                                    >
                                        <option value="">Select</option>
                                        <option value="Male">Male</option>
                                        <option value="Female">Female</option>
                                        <option value="Other">Other</option>
                                    </select>
                                    <span className="detail-label">Weight:</span>
                                    <input
                                        type="text"
                                        value={prescription.patientWeight}
                                        onChange={(e) => setPrescription({...prescription, patientWeight: e.target.value})}
                                        placeholder="e.g., 75 kg"
                                        className="detail-input"
                                    />
                                </div>
                            </div>
                        )}

                        <div className="form-group">
                            <label>Diagnosis</label>
                            <textarea
                                value={prescription.diagnosis}
                                onChange={handleDiagnosisChange}
                                placeholder="Enter diagnosis (optional)..."
                                rows="3"
                            />
                        </div>
                    </div>

                    <div className="form-section">
                        <h3>Medications</h3>

                        {suggestions.length > 0 && (
                            <div className="suggestions-box">
                                <label>Suggested Medicines:</label>
                                <div className="suggestions-list">
                                    {suggestions.map((medicineName, index) => (
                                        <button
                                            key={index}
                                            className="suggestion-chip"
                                            onClick={() => handleAddSuggestedMedicine(medicineName)}
                                            type="button"
                                        >
                                            <i className="fas fa-plus-circle"></i> {medicineName}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        <div className="medicines-list">
                            {prescription.medicines.length === 0 ? (
                                <p className="no-medicines">No medicines added yet</p>
                            ) : (
                                prescription.medicines.map((medicine, index) => (
                                    <div key={index} className="medicine-item">
                                        <div className="medicine-header">
                                            <div className="medicine-name">
                                                <strong>{medicine.name}</strong>
                                                {medicine.isCustom && <span className="custom-badge">Custom</span>}
                                            </div>
                                            <button 
                                                className="remove-btn"
                                                onClick={() => handleRemoveMedicine(index)}
                                                type="button"
                                            >
                                                <i className="fas fa-times"></i>
                                            </button>
                                        </div>
                                        <div className="medicine-details">
                                            <input
                                                type="text"
                                                value={medicine.dosage}
                                                onChange={(e) => handleMedicineDetailChange(index, 'dosage', e.target.value)}
                                                placeholder="Dosage"
                                                className="detail-input small"
                                            />
                                            <input
                                                type="text"
                                                value={medicine.duration || ''}
                                                onChange={(e) => handleMedicineDetailChange(index, 'duration', e.target.value)}
                                                placeholder="Duration"
                                                className="detail-input small"
                                            />
                                            <input
                                                type="text"
                                                value={medicine.instructions || ''}
                                                onChange={(e) => handleMedicineDetailChange(index, 'instructions', e.target.value)}
                                                placeholder="Instructions"
                                                className="detail-input large"
                                            />
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>

                        {!showCustomMedicine ? (
                            <div className="add-medicine-section">
                                <div className="medicine-selection">
                                    <select
                                        value={selectedMedicine}
                                        onChange={(e) => setSelectedMedicine(e.target.value)}
                                        className="medicine-select"
                                    >
                                        <option value="">Select from medicine DB</option>
                                        {medicines.map(medicine => (
                                            <option key={medicine.id} value={medicine.name}>
                                                {medicine.name} - {medicine.dosage}
                                            </option>
                                        ))}
                                    </select>
                                    <button 
                                        className="btn btn-secondary"
                                        onClick={handleAddMedicine}
                                        type="button"
                                    >
                                        <i className="fas fa-plus"></i> Add
                                    </button>
                                </div>
                                <button 
                                    className="btn btn-outline custom-medicine-btn"
                                    onClick={() => setShowCustomMedicine(true)}
                                    type="button"
                                >
                                    <i className="fas fa-pen"></i> Add Custom Medicine
                                </button>
                            </div>
                        ) : (
                            <div className="custom-medicine-form">
                                <h4>Add Custom Medicine</h4>
                                <div className="form-row">
                                    <input
                                        type="text"
                                        placeholder="Medicine Name *"
                                        value={customMedicine.name}
                                        onChange={(e) => setCustomMedicine({...customMedicine, name: e.target.value})}
                                        className="form-input"
                                    />
                                    <input
                                        type="text"
                                        placeholder="Dosage *"
                                        value={customMedicine.dosage}
                                        onChange={(e) => setCustomMedicine({...customMedicine, dosage: e.target.value})}
                                        className="form-input"
                                    />
                                </div>
                                <div className="form-row">
                                    <input
                                        type="text"
                                        placeholder="Duration (e.g., 7 days)"
                                        value={customMedicine.duration}
                                        onChange={(e) => setCustomMedicine({...customMedicine, duration: e.target.value})}
                                        className="form-input"
                                    />
                                    <input
                                        type="text"
                                        placeholder="Instructions"
                                        value={customMedicine.instructions}
                                        onChange={(e) => setCustomMedicine({...customMedicine, instructions: e.target.value})}
                                        className="form-input"
                                    />
                                </div>
                                <div className="custom-medicine-actions">
                                    <button 
                                        className="btn btn-success"
                                        onClick={handleAddCustomMedicine}
                                        type="button"
                                    >
                                        <i className="fas fa-check"></i> Add
                                    </button>
                                    <button 
                                        className="btn btn-outline"
                                        onClick={() => setShowCustomMedicine(false)}
                                        type="button"
                                    >
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="form-section">
                        <h3>Additional Notes</h3>
                        <textarea
                            value={prescription.notes}
                            onChange={(e) => setPrescription({...prescription, notes: e.target.value})}
                            placeholder="Additional instructions (optional)..."
                            rows="3"
                        />
                    </div>

                    <div className="form-actions">
                        <button 
                            className="btn btn-primary"
                            onClick={handleGeneratePrescription}
                            type="button"
                        >
                            <i className="fas fa-file-pdf"></i> Generate Prescription
                        </button>
                        <button 
                            className="btn btn-outline"
                            onClick={handleClearPrescription}
                            type="button"
                        >
                            <i className="fas fa-redo"></i> Clear
                        </button>
                    </div>
                </div>

                {/* Right Column - Preview */}
                <div className="prescription-preview-container">
                    <h3>Prescription Preview</h3>
                    <div className="preview-card">
                        <div className="preview-header">
                            <div className="clinic-info">
                                <h4><i className="fas fa-heartbeat"></i> MediCare Clinic</h4>
                                <p>123 Health Street, Medical City</p>
                                <p>Phone: (123) 456-7890</p>
                            </div>
                            <div className="preview-date">
                                <p>Date: {new Date().toLocaleDateString()}</p>
                            </div>
                        </div>

                        <div className="preview-patient">
                            <h5>Patient Information</h5>
                            <div className="preview-row">
                                <span className="preview-label">Name:</span>
                                <span className="preview-value">
                                    {selectedPatient?.name || 'Not selected'}
                                </span>
                            </div>
                            {prescription.patientAge && (
                                <div className="preview-row">
                                    <span className="preview-label">Age:</span>
                                    <span className="preview-value">{prescription.patientAge}</span>
                                </div>
                            )}
                            {prescription.patientGender && (
                                <div className="preview-row">
                                    <span className="preview-label">Gender:</span>
                                    <span className="preview-value">{prescription.patientGender}</span>
                                </div>
                            )}
                            {prescription.patientWeight && (
                                <div className="preview-row">
                                    <span className="preview-label">Weight:</span>
                                    <span className="preview-value">{prescription.patientWeight}</span>
                                </div>
                            )}
                            {prescription.diagnosis && (
                                <div className="preview-row">
                                    <span className="preview-label">Diagnosis:</span>
                                    <span className="preview-value">{prescription.diagnosis}</span>
                                </div>
                            )}
                        </div>

                        <div className="preview-medicines">
                            <h5>Prescribed Medicines</h5>
                            {prescription.medicines.length === 0 ? (
                                <p className="no-items">No medicines added yet</p>
                            ) : (
                                prescription.medicines.map((medicine, index) => (
                                    <div key={index} className="preview-medicine-item">
                                        <div className="medicine-main">
                                            <strong>{medicine.name}</strong> - {medicine.dosage}
                                            {medicine.isCustom && <span className="custom-tag">Custom</span>}
                                        </div>
                                        {medicine.duration && (
                                            <div className="medicine-detail">Duration: {medicine.duration}</div>
                                        )}
                                        {medicine.instructions && (
                                            <div className="medicine-detail">Instructions: {medicine.instructions}</div>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>

                        {prescription.notes && (
                            <div className="preview-notes">
                                <h5>Additional Notes</h5>
                                <p>{prescription.notes}</p>
                            </div>
                        )}

                        <div className="preview-footer">
                            <div className="doctor-signature">
                                <p>___________________</p>
                                <p><strong>Dr. John Smith</strong></p>
                                <p>MBBS, MD</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default PrescriptionGenerator;
